import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.c3r8iWL8.js";const u=JSON.parse('{"title":"SOP-002: ADR Lifecycle","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-002-adr-lifecycle.md","filePath":"sops/SOP-002-adr-lifecycle.md","lastUpdated":1782929962000}'),i={name:"sops/SOP-002-adr-lifecycle.md"};function d(s,e,l,n,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="sop-002-adr-lifecycle" tabindex="-1">SOP-002: ADR Lifecycle <a class="header-anchor" href="#sop-002-adr-lifecycle" aria-label="Permalink to &quot;SOP-002: ADR Lifecycle&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> Architect · <strong>Gate:</strong> G1 (partial)</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Create, review, accept, and publish Architecture Decision Records. AI drafts; architect <strong>must</strong> accept before the decision binds the org or AI agents.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>ARCH</td><td><strong>A</strong> — accept/reject ADR</td></tr><tr><td>DEV</td><td>R — propose, draft via AI</td></tr><tr><td>SEC</td><td>C — security implications</td></tr><tr><td>SRE</td><td>C — operability, cost</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Ticket flagged <code>needs-adr</code> OR implementation blocked on unresolved design choice</li><li>Planning agent or MCP access to existing Accepted ADR corpus</li></ul><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><h3 id="create" tabindex="-1">Create <a class="header-anchor" href="#create" aria-label="Permalink to &quot;Create&quot;">​</a></h3><ol><li><strong>Identify decision</strong> — One ADR per decision (not per feature). Name: <code>NNNN-short-title.md</code>.</li><li><strong>AI draft</strong> — Prompt planning agent with: context, constraints, existing ADRs, AWS preference. Output status: <code>proposed</code>.</li><li><strong>Minimum content</strong> — Context, ≥ 2 options with trade-offs, recommendation, consequences, links to tickets/specs.</li><li><strong>Open PR</strong> — Path: <code>docs/adr/NNNN-*.md</code>. Tag ARCH + SEC (if external exposure).</li></ol><h3 id="review" tabindex="-1">Review <a class="header-anchor" href="#review" aria-label="Permalink to &quot;Review&quot;">​</a></h3><ol start="5"><li><strong>Architect review</strong> — Validate options are real, recommendation fits NFRs, no conflict with Accepted ADRs.</li><li><strong>Amend</strong> — AI may refine per comments; human edits always allowed.</li><li><strong>Accept or reject</strong> — ARCH sets status <code>accepted</code> or <code>rejected</code> in front matter. Rejected ADRs stay in Git with rationale.</li></ol><h3 id="supersede" tabindex="-1">Supersede <a class="header-anchor" href="#supersede" aria-label="Permalink to &quot;Supersede&quot;">​</a></h3><ol start="8"><li>When decision changes, create new ADR; mark old <code>superseded</code> with link to successor. Never edit Accepted ADR body in place.</li></ol><h3 id="publish" tabindex="-1">Publish <a class="header-anchor" href="#publish" aria-label="Permalink to &quot;Publish&quot;">​</a></h3><ol start="9"><li>Merge PR → triggers <a href="./SOP-009-artifact-publish.html">SOP-009</a> indexing.</li></ol><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><ul><li>[ ] Status is <code>accepted</code> (or <code>rejected</code> with documented reason)</li><li>[ ] No unresolved conflict with other Accepted ADRs</li><li>[ ] Linked from spec (<code>x-adr</code>) or ticket if applicable</li><li>[ ] Indexed within 15 min of merge (SOP-009)</li></ul><h2 id="sla-escalation" tabindex="-1">SLA &amp; escalation <a class="header-anchor" href="#sla-escalation" aria-label="Permalink to &quot;SLA &amp; escalation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Milestone</th><th>SLA</th></tr></thead><tbody><tr><td>Proposed → Accepted</td><td>≤ 3 business days</td></tr><tr><td>Weekly ARB backlog</td><td>Review all Proposed &gt; 5 days</td></tr></tbody></table><p>Escalation: cross-team conflict → Architecture review board (weekly).</p><h2 id="ai-boundaries" tabindex="-1">AI boundaries <a class="header-anchor" href="#ai-boundaries" aria-label="Permalink to &quot;AI boundaries&quot;">​</a></h2><table tabindex="0"><thead><tr><th>AI may</th><th>AI may not</th></tr></thead><tbody><tr><td>Draft options and recommendation</td><td>Set status to <code>accepted</code></td></tr><tr><td>Retrieve related ADRs</td><td>Merge PR</td></tr><tr><td>Flag conflicts with prior ADRs</td><td>Override architect decision</td></tr></tbody></table><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-003-spec-approval.html">SOP-003</a> · <a href="./SOP-009-artifact-publish.html">SOP-009</a> · <a href="./../GOVERNANCE.html">GOVERNANCE.md</a></li></ul>',26)])])}const f=t(i,[["render",d]]);export{u as __pageData,f as default};
